frappe.web_form.after_load = () => {

    // Create a new button element
    const button = document.createElement("button");
    button.innerHTML = "Sample Documents";
    button.classList.add("edit-button", "btn", "btn-default", "btn-sm");
    // button.style.marginLeft = "10px"; // Optional: Add some spacing between the button and other elements

    // Add a click event listener to the button
    button.addEventListener("click", () => {
      // Define the file URL you want to download or redirect to
      const fileURL = "https://drive.google.com/drive/folders/12R5VgSjLibcVRqUqwG7uWZX5sfP8cnL6";

      // If you want to redirect to the file URL
      window.open(fileURL, "_blank");
    });

    var formContentWrapper = document.querySelector(".web-form-actions");
    formContentWrapper.appendChild(button);



    const msmedNumberField = frappe.web_form.fields_dict.msmed_number;
    const msme_licenceField = frappe.web_form.fields_dict.msme_licence;
    frappe.web_form.on('mesme_present', (field, value) => {
      if (value === 'Yes') {
        msmedNumberField.toggle(true); // Show the msmed_number input box
        msmedNumberField.df.reqd = 1; // Set the msmed_number field as required
        msme_licenceField.df.reqd = 1; // Set the msme_licence field as required
      } else {
        msmedNumberField.toggle(false); // Hide the msmed_number input box
        msmedNumberField.set_value("");
        msmedNumberField.df.reqd = 0; // Set the msmed_number field as not required
        msme_licenceField.df.reqd = 0; // Set the msme_licence field as not required
      }
    });

    // Hide the msmed_number input box by default

    // Check the initial value of 'mesme_present' field
    const initialMesmePresentValue = frappe.web_form.get_value('mesme_present');
    if (initialMesmePresentValue === 'Yes') {
      const msmedNumberField = frappe.web_form.fields_dict.msmed_number;
      msmedNumberField.toggle(true); // Show the msmed_number input box
      msmedNumberField.df.reqd = 1; // Set the msmed_number field as required
      msme_licenceField.df.reqd = 1; // Set the msme_licence field as required
    }
    else {
      msmedNumberField.toggle(false);
      msmedNumberField.set_value("");
      msmedNumberField.df.reqd = 0; // Set the msmed_number field as not required
      msme_licenceField.df.reqd = 0; // Set the msme_licence field as not required
    }


    // MESME Number Validation
    frappe.web_form.fields_dict.msmed_number.$input.on("change", function () {
      const field = frappe.web_form.fields_dict.msmed_number;
      let value = field.get_value();
      const validFormat = /^UDYAM-[A-Z]{2}-\d{2}-\d{7}$/;



      // Convert lowercase letters to uppercase
      value = value.toUpperCase();

      if (!validFormat.test(value)) {
        // Invalid format, show an error message or take appropriate action
        const errorMessage = 'Invalid MSME number. Please enter a valid MSME number.';
        const formatSample = 'Example: UDYAM-XX-00-0000000'; // Format sample for the MSME number
        frappe.msgprint(`${errorMessage}<br><strong>Format sample:</strong> ${formatSample}`);
        field.set_value("");
      }



    });

    // Submit form handler
    frappe.web_form.on('submit', () => {
      const mesmePresentValue = frappe.web_form.get_value('mesme_present');
      const msmedNumberValue = frappe.web_form.get_value('msmed_number');

      if (mesmePresentValue === 'Yes' && !msmedNumberValue) {
        // If 'mesme_present' is 'Yes' and 'msmed_number' is empty, prevent form submission and display an error message
        frappe.msgprint('Please provide a value for msmed_number.');
        return false;
      }

      // Allow form submission for other cases
      return true;
    });

    //----End Of frappe.web_form.after_load



  };

  // GST Validation
  frappe.web_form.fields_dict.gst_number.$input.on("change", function () {
    const gst_field = frappe.web_form.fields_dict.gst_number;
    let value = gst_field.get_value();

    // Remove any spaces or special characters from the value
    value = value.replace(/\s+/g, "").toUpperCase();

    const gstPattern = /^([0-9]{2})([A-Z]{5})([0-9]{4})([A-Z]{1})([1-9A-Za-z]{1})([Z]{1})([0-9A-Z]{1})$/i;

    if (!gstPattern.test(value)) {
      // Invalid GST format, show an error message or take appropriate action
      //frappe.msgprint("Invalid GST value. Please enter a valid GST number.");
      const errorMessage = 'Invalid GST value. Please enter a valid GST  number.';
      const formatSample = 'Example: 22AAAAA0000A1Z5'; // Format sample for the PAN Card number
      frappe.msgprint(`${errorMessage}<br><strong>Format sample:</strong> ${formatSample}`);
      gst_field.set_value("");
    } else {
      // Reformat the GST number to the desired format (example: 12ABCDE1234F1Z5)
      const formattedValue = value.replace(gstPattern, "$1$2$3$4$5$6$7");
      gst_field.set_value(formattedValue);  // Set the updated value back to the field
    }
  });
